#include <stdio.h>
#include <stdlib.h>
int main(){
    int M,N,P;
    if(scanf("%d %d",&M,&N)!=2) return 0;
    long long **A = (long long**)malloc(M*sizeof(long long*));
    for(int i=0;i<M;++i){
        A[i]=(long long*)malloc(N*sizeof(long long));
        for(int j=0;j<N;++j) scanf("%lld",&A[i][j]);
    }
    int n_check;
    if(scanf("%d %d",&n_check,&P)!=2) return 0;
    N = n_check; // ensure consistency
    long long **B = (long long**)malloc(N*sizeof(long long*));
    for(int i=0;i<N;++i){
        B[i]=(long long*)malloc(P*sizeof(long long));
        for(int j=0;j<P;++j) scanf("%lld",&B[i][j]);
    }
    for(int i=0;i<M;++i){
        for(int j=0;j<P;++j){
            long long sum=0;
            for(int k=0;k<N;++k) sum+=A[i][k]*B[k][j];
            printf("%lld",sum);
            if(j<P-1) printf(" ");
        }
        printf("\n");
    }
    for(int i=0;i<M;++i) free(A[i]);
    free(A);
    for(int i=0;i<N;++i) free(B[i]);
    free(B);
    return 0;
}

