import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        Integer MObj = fs.nextIntOrNull();
        if (MObj == null) return;
        int M = MObj;
        int N = fs.nextInt();
        long[][] A = new long[M][N];
        for (int i = 0; i < M; i++)
            for (int j = 0; j < N; j++)
                A[i][j] = fs.nextLong();
        int nCheck = fs.nextInt();
        int P = fs.nextInt();
        N = nCheck; // ensure consistency
        long[][] B = new long[N][P];
        for (int i = 0; i < N; i++)
            for (int j = 0; j < P; j++)
                B[i][j] = fs.nextLong();
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < P; j++) {
                long sum = 0;
                for (int k = 0; k < N; k++) sum += A[i][k] * B[k][j];
                sb.append(sum);
                if (j < P - 1) sb.append(' ');
            }
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final BufferedReader br;
        private StringTokenizer st;
        FastScanner(InputStream is) { br = new BufferedReader(new InputStreamReader(is)); }
        String next() throws IOException {
            while (st == null || !st.hasMoreElements()) {
                String line = br.readLine();
                if (line == null) return null;
                st = new StringTokenizer(line);
            }
            return st.nextToken();
        }
        Integer nextIntOrNull() throws IOException { String s = next(); return s == null ? null : Integer.parseInt(s); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

