const fs = require('fs');
const tokens = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (tokens.length === 0) process.exit(0);
const M = Number(tokens[idx++]);
let N = Number(tokens[idx++]);
const A = Array.from({ length: M }, () => {
  const row = [];
  for (let j = 0; j < N; j++) row.push(Number(tokens[idx++]));
  return row;
});
const nCheck = Number(tokens[idx++]);
const P = Number(tokens[idx++]);
N = nCheck;
const B = Array.from({ length: N }, () => {
  const row = [];
  for (let j = 0; j < P; j++) row.push(Number(tokens[idx++]));
  return row;
});
let output = '';
for (let i = 0; i < M; i++) {
  const rowVals = [];
  for (let j = 0; j < P; j++) {
    let sum = 0;
    for (let k = 0; k < N; k++) sum += A[i][k] * B[k][j];
    rowVals.push(sum);
  }
  output += rowVals.join(' ') + '\n';
}
process.stdout.write(output);

